import pytest
from fastapi.testclient import TestClient
from app import app

@pytest.fixture
def client():
    return TestClient(app)

@pytest.fixture
def auth_headers(client):
    r = client.post("/auth/login", json={"email": "test@x.com", "password": "pw"})
    return {"Authorization": f"Bearer {r.json()['access_token']}"}

class TestUsers:
    def test_create_user(self, client, auth_headers):
        r = client.post("/users", json={"name": "A", "email": "a@b.com"}, headers=auth_headers)
        assert r.status_code == 201
        assert r.json()["name"] == "A"

    def test_not_found_returns_404(self, client, auth_headers):
        r = client.get("/users/nonexistent", headers=auth_headers)
        assert r.status_code == 404

const { Pact } = require('@pact-foundation/pact');

const provider = new Pact({ consumer: 'Frontend', provider: 'UserAPI', port: 8080 });

describe('User API contract', () => {
  beforeAll(() => provider.setup());
  afterAll(() => provider.finalize());

  it('gets user by id', async () => {
    await provider.addInteraction({
      state: 'user exists',
      uponReceiving: 'GET /users/123',
      withRequest: { method: 'GET', path: '/users/123', headers: { Authorization: 'Bearer token' } },
      willRespondWith: {
        status: 200,
        body: { id: Matchers.string('123'), name: Matchers.string('John'), email: Matchers.email() },
      },
    });
    const response = await userClient.getUser('123');
    expect(response.id).toBe('123');
  });
});
